class Solution {
    public boolean isRationalEqual(String s, String t) {
        return toFraction(s).equals(toFraction(t));
    }

    private String toFraction(String s) {
        if (s.indexOf('.') == -1) {
            return s + "/1";
        }
        int integerPartLength = getIntegerPartLength(s);
        String integerPart = s.substring(0, integerPartLength);
        String decimalPart = s.substring(integerPartLength);
        int decimalPointIndex = decimalPart.indexOf('.');
        if (decimalPointIndex != -1) {
            decimalPart = decimalPart.substring(decimalPointIndex + 1);
        }
        int openParenthesisIndex = decimalPart.indexOf('(');
        if (openParenthesisIndex != -1) {
            String nonRepeatingPart = decimalPart.substring(0, openParenthesisIndex);
            String repeatingPart = decimalPart.substring(openParenthesisIndex + 1, decimalPart.length() - 1);
            return toFraction(integerPart, nonRepeatingPart, repeatingPart);
        } else {
            return toFraction(integerPart, decimalPart, "");
        }
    }

    private int getIntegerPartLength(String s) {
        int i = 0;
        while (i < s.length() && s.charAt(i) != '.') {
            i++;
        }
        return i;
    }

    private String toFraction(String integerPart, String nonRepeatingPart, String repeatingPart) {
        long integer = Long.parseLong(integerPart);
        long denominator = 1;
        long numerator = integer;
        if (!nonRepeatingPart.isEmpty() || !repeatingPart.isEmpty()) {
            String decimalPart = nonRepeatingPart + repeatingPart;
            denominator = (long) Math.pow(10, decimalPart.length());
            numerator = integer * denominator + Long.parseLong(nonRepeatingPart);
            if (!repeatingPart.isEmpty()) {
                denominator = (long) Math.pow(10, repeatingPart.length()) - 1;
                numerator = (numerator * (denominator + 1) - Long.parseLong(nonRepeatingPart)) / 10;
            }
        }
        long gcd = gcd(numerator, denominator);
        return (numerator / gcd) + "/" + (denominator / gcd);
    }

    private long gcd(long a, long b) {
        if (b == 0) {
            return a;
        }
        return gcd(b, a % b);
    }
}
